/**
 * lib/auth.ts
 * JWT-authenticatie helpers met jose.
 * Demo-login: credentials komen uit .env (geen echte gebruikersdatabase nodig).
 */

import { SignJWT, jwtVerify } from 'jose';
import { cookies } from 'next/headers';

export interface UserPayload {
  userId: string;
  email:  string;
  role:   'admin' | 'user';
}

const secret = new TextEncoder().encode(
  process.env.JWT_SECRET ?? 'insecure-fallback-change-me'
);

/** Maakt een gesigneerd JWT-token aan (geldig 24 uur). */
export async function signToken(payload: UserPayload): Promise<string> {
  return new SignJWT({ ...payload })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('24h')
    .sign(secret);
}

/** Verifieert een JWT-token. Gooit een fout bij ongeldig/verlopen token. */
export async function verifyToken(token: string): Promise<UserPayload> {
  const { payload } = await jwtVerify(token, secret);
  return payload as unknown as UserPayload;
}

/** Haalt de huidige gebruiker op vanuit de cookie (server-side). */
export async function getUser(): Promise<UserPayload | null> {
  try {
    const store = await cookies();
    const token = store.get('auth-token')?.value;
    if (!token) return null;
    return await verifyToken(token);
  } catch {
    return null;
  }
}

/**
 * Controleert demo-credentials vanuit .env.
 * Retourneert UserPayload bij succes, null bij mislukte login.
 */
export function checkDemoCredentials(
  email: string,
  password: string
): UserPayload | null {
  const adminEmail    = process.env.ADMIN_EMAIL        ?? 'admin@peterallesweter.be';
  const adminPassword = process.env.ADMIN_PASSWORD     ?? 'admin123';
  const demoEmail     = process.env.DEMO_USER_EMAIL    ?? 'demo@peterallesweter.be';
  const demoPassword  = process.env.DEMO_USER_PASSWORD ?? 'demo123';

  if (email === adminEmail && password === adminPassword)
    return { userId: 'admin-1', email, role: 'admin' };

  if (email === demoEmail && password === demoPassword)
    return { userId: 'demo-1', email, role: 'user' };

  return null;
}

