/**
 * app/api/auth/route.ts
 * Authenticatie endpoints.
 * POST  — inloggen (retourneert httpOnly JWT-cookie)
 * DELETE — uitloggen (verwijdert cookie)
 */

import { NextRequest, NextResponse } from 'next/server';
import { signToken, checkDemoCredentials } from '@/lib/auth';

/** POST /api/auth */
export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { email, password } = body;

    // Basis validatie
    if (!email || !password || typeof email !== 'string' || typeof password !== 'string') {
      return NextResponse.json({ error: 'E-mail en wachtwoord zijn verplicht.' }, { status: 400 });
    }

    // Saniteer input
    const cleanEmail    = email.trim().toLowerCase().slice(0, 100);
    const cleanPassword = password.trim().slice(0, 100);

    const user = checkDemoCredentials(cleanEmail, cleanPassword);
    if (!user) {
      return NextResponse.json({ error: 'Ongeldige inloggegevens.' }, { status: 401 });
    }

    const token = await signToken(user);

    const res = NextResponse.json({
      success: true,
      user: { email: user.email, role: user.role },
    });

    res.cookies.set('auth-token', token, {
      httpOnly: true,
      secure:   process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge:   24 * 60 * 60, // 24 uur
      path:     '/',
    });

    console.log(`[Auth] Ingelogd: ${cleanEmail} (${user.role})`);
    return res;
  } catch (err) {
    console.error('[Auth] Fout:', err);
    return NextResponse.json({ error: 'Interne serverfout.' }, { status: 500 });
  }
}

/** DELETE /api/auth */
export async function DELETE() {
  const res = NextResponse.json({ success: true });
  res.cookies.delete('auth-token');
  return res;
}

