/**
 * app/api/vehicles/route.ts
 * CRUD-endpoints voor voertuigen.
 * GET    — publiek (voor chat-context & overzicht)
 * POST   — admin vereist
 * PUT    — admin vereist
 * DELETE — admin vereist
 */

import { NextRequest, NextResponse } from 'next/server';
import { getPool, sql }              from '@/lib/db';
import { getUser }                   from '@/lib/auth';

/** GET /api/vehicles */
export async function GET() {
  try {
    const pool   = await getPool();
    const result = await pool.request().query(`
      SELECT v.*, l.name AS locationName, l.city AS locationCity
      FROM   Vehicles v
      LEFT   JOIN RentalLocations l ON v.locationId = l.id
      ORDER  BY v.brand, v.model
    `);
    return NextResponse.json(result.recordset);
  } catch (err) {
    console.error('[Vehicles] GET mislukt:', err);
    return NextResponse.json({ error: 'Database-fout.' }, { status: 500 });
  }
}

/** POST /api/vehicles */
export async function POST(request: NextRequest) {
  const user = await getUser();
  if (user?.role !== 'admin')
    return NextResponse.json({ error: 'Niet geautoriseerd.' }, { status: 403 });

  try {
    const b = await request.json();
    if (!b.brand || !b.model || !b.type || b.dailyPrice == null)
      return NextResponse.json({ error: 'brand, model, type en dailyPrice zijn verplicht.' }, { status: 400 });

    const pool   = await getPool();
    const result = await pool.request()
      .input('brand',              sql.NVarChar(100),      b.brand.trim())
      .input('model',              sql.NVarChar(100),      b.model.trim())
      .input('type',               sql.NVarChar(50),       b.type)
      .input('seats',              sql.Int,                b.seats      ?? 5)
      .input('engineCC',           sql.Int,                b.engineCC   ?? null)
      .input('dailyPrice',         sql.Decimal(10, 2),     parseFloat(b.dailyPrice))
      .input('availabilityStatus', sql.NVarChar(20),       b.availabilityStatus ?? 'available')
      .input('locationId',         sql.Int,                b.locationId ?? null)
      .input('lastUpdated',        sql.DateTime,           new Date())
      .query(`
        INSERT INTO Vehicles
          (brand, model, type, seats, engineCC, dailyPrice, availabilityStatus, locationId, lastUpdated)
        OUTPUT INSERTED.*
        VALUES
          (@brand, @model, @type, @seats, @engineCC, @dailyPrice, @availabilityStatus, @locationId, @lastUpdated)
      `);

    return NextResponse.json(result.recordset[0], { status: 201 });
  } catch (err) {
    console.error('[Vehicles] POST mislukt:', err);
    return NextResponse.json({ error: 'Database-fout.' }, { status: 500 });
  }
}

/** PUT /api/vehicles */
export async function PUT(request: NextRequest) {
  const user = await getUser();
  if (user?.role !== 'admin')
    return NextResponse.json({ error: 'Niet geautoriseerd.' }, { status: 403 });

  try {
    const b = await request.json();
    if (!b.id) return NextResponse.json({ error: 'id is verplicht.' }, { status: 400 });

    const pool   = await getPool();
    const result = await pool.request()
      .input('id',                 sql.Int,                b.id)
      .input('brand',              sql.NVarChar(100),      b.brand?.trim())
      .input('model',              sql.NVarChar(100),      b.model?.trim())
      .input('type',               sql.NVarChar(50),       b.type)
      .input('seats',              sql.Int,                b.seats)
      .input('engineCC',           sql.Int,                b.engineCC   ?? null)
      .input('dailyPrice',         sql.Decimal(10, 2),     parseFloat(b.dailyPrice))
      .input('availabilityStatus', sql.NVarChar(20),       b.availabilityStatus)
      .input('locationId',         sql.Int,                b.locationId ?? null)
      .input('lastUpdated',        sql.DateTime,           new Date())
      .query(`
        UPDATE Vehicles
        SET brand              = @brand,
            model              = @model,
            type               = @type,
            seats              = @seats,
            engineCC           = @engineCC,
            dailyPrice         = @dailyPrice,
            availabilityStatus = @availabilityStatus,
            locationId         = @locationId,
            lastUpdated        = @lastUpdated
        OUTPUT INSERTED.*
        WHERE id = @id
      `);

    if (!result.recordset.length)
      return NextResponse.json({ error: 'Voertuig niet gevonden.' }, { status: 404 });

    return NextResponse.json(result.recordset[0]);
  } catch (err) {
    console.error('[Vehicles] PUT mislukt:', err);
    return NextResponse.json({ error: 'Database-fout.' }, { status: 500 });
  }
}

/** DELETE /api/vehicles?id=123 */
export async function DELETE(request: NextRequest) {
  const user = await getUser();
  if (user?.role !== 'admin')
    return NextResponse.json({ error: 'Niet geautoriseerd.' }, { status: 403 });

  const id = Number(new URL(request.url).searchParams.get('id'));
  if (!id) return NextResponse.json({ error: 'id is verplicht.' }, { status: 400 });

  try {
    const pool = await getPool();
    await pool.request()
      .input('id', sql.Int, id)
      .query('DELETE FROM Vehicles WHERE id = @id');
    return NextResponse.json({ success: true });
  } catch (err) {
    console.error('[Vehicles] DELETE mislukt:', err);
    return NextResponse.json({ error: 'Database-fout.' }, { status: 500 });
  }
}

