import { NextRequest, NextResponse } from 'next/server';
import { getAllConversations, getConversationMessages } from '@/lib/db';
import { getUser } from '@/lib/auth';

/** GET /api/conversations — admin */
export async function GET(request: NextRequest) {
  const user = await getUser();
  if (user?.role !== 'admin')
    return NextResponse.json({ error: 'Niet geautoriseerd.' }, { status: 403 });

  const convId = new URL(request.url).searchParams.get('id');

  try {
    if (convId) {
      // Detail: berichten van één conversatie
      const messages = await getConversationMessages(convId);
      return NextResponse.json(messages);
    } else {
      // Lijst: alle conversaties
      const conversations = await getAllConversations(100);
      return NextResponse.json(conversations);
    }
  } catch (err) {
    console.error('[Conversations] GET mislukt:', err);
    return NextResponse.json({ error: 'Database-fout.' }, { status: 500 });
  }
}

