/**
 * components/ChatMessage.tsx
 * Toont één chatbericht (gebruiker of bot) met tijdstip en avatar.
 */
'use client';

import { Car, User } from 'lucide-react';
import { cn } from '@/lib/utils';

interface Props {
  role:      'user' | 'assistant';
  content:   string;
  timestamp?: string;
  streaming?: boolean; // knipperende cursor tijdens streamen
}

export function ChatMessage({ role, content, timestamp, streaming }: Props) {
  const isUser = role === 'user';

  return (
    <div className={cn('flex gap-3 px-4 py-2', isUser ? 'flex-row-reverse' : 'flex-row')}>
      {/* Avatar */}
      <div
        className={cn(
          'flex h-8 w-8 shrink-0 items-center justify-center rounded-full text-white',
          isUser ? 'bg-brand-600' : 'bg-gray-700'
        )}
      >
        {isUser ? <User size={16} /> : <Car size={16} />}
      </div>

      {/* Bel */}
      <div className={cn('max-w-[75%] space-y-1', isUser ? 'items-end' : 'items-start')}>
        <div
          className={cn(
            'rounded-2xl px-4 py-2.5 text-sm leading-relaxed whitespace-pre-wrap',
            isUser
              ? 'rounded-tr-sm bg-brand-600 text-white'
              : 'rounded-tl-sm bg-gray-100 text-gray-900',
            streaming && !isUser && 'streaming-cursor'
          )}
        >
          {content}
        </div>
        {timestamp && (
          <p className="px-1 text-xs text-gray-400">
            {new Date(timestamp).toLocaleTimeString('nl-BE', {
              hour:   '2-digit',
              minute: '2-digit',
            })}
          </p>
