 * Toont één chatbericht (gebruiker of bot) met tijdstip en avatar.
 */
'use client';

import { Car, User } from 'lucide-react';
import { cn } from '@/lib/utils';

interface Props {
  role:      'user' | 'assistant';
  content:   string;
  timestamp?: string;
  streaming?: boolean; // knipperende cursor tijdens streamen
}

export function ChatMessage({ role, content, timestamp, streaming }: Props) {
