/**
 * components/VehicleCard.tsx
 * Toont een voertuig met prijs, type en beschikbaarheidsstatus.
 */
'use client';

import { Car, MapPin, Users, Zap } from 'lucide-react';
import { Badge }                    from './ui/badge';
import { Card, CardContent }        from './ui/card';
import type { Vehicle }             from '@/types';

interface Props {
  vehicle: Vehicle;
}

const STATUS_LABEL: Record<string, string> = {
  available:   'Beschikbaar',
  rented:      'Verhuurd',
  maintenance: 'In onderhoud',
};

const TYPE_LABEL: Record<string, string> = {
  sedan:       'Sedan',
  suv:         'SUV',
  hatchback:   'Hatchback',
  van:         'Bestelwagen',
  electric:    'Elektrisch',
  convertible: 'Cabriolet',
  truck:       'Truck',
};

export function VehicleCard({ vehicle }: Props) {
  const statusVariant =
    vehicle.availabilityStatus === 'available'   ? 'available'   :
    vehicle.availabilityStatus === 'maintenance' ? 'maintenance' :
    'rented';

  return (
    <Card className="hover:shadow-md transition-shadow duration-200">
      <CardContent className="p-4">
        {/* Merk & model */}
        <div className="flex items-start justify-between gap-2">
          <div>
            <p className="font-semibold text-gray-900 leading-tight">
              {vehicle.brand} {vehicle.model}
            </p>
            <p className="text-xs text-gray-500 mt-0.5">{TYPE_LABEL[vehicle.type] ?? vehicle.type}</p>
          </div>
          <Badge variant={statusVariant as 'available' | 'rented' | 'maintenance'}>
            {STATUS_LABEL[vehicle.availabilityStatus]}
          </Badge>
        </div>

        {/* Prijs */}
        <div className="mt-3 flex items-baseline gap-1">
          <span className="text-2xl font-bold text-brand-600">
            €{Number(vehicle.dailyPrice).toFixed(0)}
          </span>
          <span className="text-xs text-gray-500">/dag</span>
        </div>

        {/* Details */}
        <div className="mt-3 flex flex-wrap gap-3 text-xs text-gray-600">
          <span className="flex items-center gap-1">
            <Users size={12} />
            {vehicle.seats} zitpl.
          </span>
          {vehicle.engineCC ? (
            <span className="flex items-center gap-1">
              <Car size={12} />
              {vehicle.engineCC}cc
            </span>
          ) : (
            <span className="flex items-center gap-1 text-green-600">
              <Zap size={12} />
              Elektrisch
            </span>
          )}
          {vehicle.locationCity && (
            <span className="flex items-center gap-1">
              <MapPin size={12} />
              {vehicle.locationCity}
            </span>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

