     1→/**
     2→ * lib/db.ts
     3→ * Singleton SQL Server connection pool en query helpers.
     4→ * Gebruikt de mssql driver met parameterized queries (geen SQL-injectie mogelijk).
     5→ */
     6→
     7→import sql from 'mssql';
     8→
     9→// ---------------------------------------------------------------
    10→// Connection pool configuratie vanuit .env
    11→// ---------------------------------------------------------------
    12→
    13→/**
    14→ * Parst "SERVER\INSTANCE" of "SERVER" naar aparte config velden.
    15→ */
    16→function parseServer(raw: string): { server: string; instanceName?: string } {
    17→  const [server, instanceName] = (raw || '').split('\\');
    18→  return { server, instanceName: instanceName || undefined };
    19→}
    20→
    21→const { server, instanceName } = parseServer(process.env.DB_SERVER || '');
    22→
    23→const dbConfig: sql.config = {
    24→  server,
    25→  database:  process.env.DB_DATABASE || 'Chatbotdb',
    26→  user:      process.env.DB_USER     || '',
    27→  password:  process.env.DB_PASSWORD || '',
    28→  options: {
    29→    instanceName,
    30→    trustServerCertificate: true, // nodig voor dev zonder geldig SSL-certificaat
    31→    enableArithAbort: true,
    32→  },
    33→  pool: {
    34→    max: 10,
    35→    min: 0,
    36→    idleTimeoutMillis: 30_000,
    37→  },
    38→  connectionTimeout: 15_000,
    39→  requestTimeout:    30_000,
    40→};
    41→
    42→// ---------------------------------------------------------------
    43→// Singleton pool
    44→// ---------------------------------------------------------------
    45→
    46→let _pool: sql.ConnectionPool | null = null;
    47→
    48→/**
    49→ * Geeft de actieve connection pool terug.
    50→ * Maakt bij eerste aanroep de verbinding aan.
    51→ */
    52→export async function getPool(): Promise<sql.ConnectionPool> {
    53→  if (_pool?.connected) return _pool;
    54→
    55→  try {
    56→    _pool = await sql.connect(dbConfig);
    57→    console.log('[DB] ✅ Verbonden met SQL Server');
    58→    return _pool;
    59→  } catch (err) {
    60→    console.error('[DB] ❌ Verbinding mislukt:', err);
    61→    throw err;
    62→  }
    63→}
    64→
    65→export { sql };
    66→
    67→// ---------------------------------------------------------------
    68→// Voertuig queries
    69→// ---------------------------------------------------------------
    70→
    71→/** Haalt alle voertuigen op met locatieinfo. */
    72→export async function getVehicles() {
    73→  const pool = await getPool();
    74→  const result = await pool.request().query(`
    75→    SELECT v.id, v.brand, v.model, v.type, v.seats, v.engineCC,
    76→           v.dailyPrice, v.availabilityStatus, v.locationId, v.lastUpdated,
    77→           l.name AS locationName, l.city AS locationCity
    78→    FROM Vehicles v
    79→    LEFT JOIN RentalLocations l ON v.locationId = l.id
    80→    ORDER BY v.brand, v.model
    81→  `);
    82→  return result.recordset;
    83→}
    84→
    85→/** Haalt één voertuig op via ID. */
    86→export async function getVehicleById(id: number) {
    87→  const pool = await getPool();
    88→  const result = await pool.request()
    89→    .input('id', sql.Int, id)
    90→    .query('SELECT * FROM Vehicles WHERE id = @id');
    91→  return result.recordset[0] ?? null;
    92→}
    93→
    94→// ---------------------------------------------------------------
    95→// Locatie queries
    96→// ---------------------------------------------------------------
    97→
    98→/** Haalt alle actieve verhuurlocaties op. */
    99→export async function getLocations() {
   100→  const pool = await getPool();
   101→  const result = await pool.request().query(`
   102→    SELECT id, name, city, address, phone, email, isActive
   103→    FROM   RentalLocations
   104→    WHERE  isActive = 1
   105→    ORDER  BY city
   106→  `);
   107→  return result.recordset;
   108→}
   109→
   110→// ---------------------------------------------------------------
   111→// Conversatie / berichten
   112→// ---------------------------------------------------------------
   113→
   114→/** Maakt een nieuwe conversatie aan en retourneert het conversationId. */
   115→export async function createConversation(userId: string): Promise<string> {
   116→  const pool = await getPool();
   117→  const conversationId = `conv_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
   118→  await pool.request()
   119→    .input('conversationId', sql.NVarChar(100), conversationId)
   120→    .input('userId',         sql.NVarChar(100), userId)
   121→    .input('timestamp',      sql.DateTime,      new Date())
   122→    .query(`
   123→      INSERT INTO Conversations (conversationId, userId, timestamp)
   124→      VALUES (@conversationId, @userId, @timestamp)
   125→    `);
   126→  return conversationId;
   127→}
   128→
   129→/** Slaat één chatbericht op. */
   130→export async function saveMessage(params: {
   131→  conversationId: string;
   132→  role: 'user' | 'assistant' | 'system';
   133→  content: string;
   134→  llmModelUsed?: string;
   135→}) {
   136→  const pool = await getPool();
   137→  await pool.request()
   138→    .input('conversationId', sql.NVarChar(100),  params.conversationId)
   139→    .input('role',           sql.NVarChar(20),   params.role)
   140→    .input('content',        sql.NVarChar(sql.MAX), params.content)
   141→    .input('llmModelUsed',   sql.NVarChar(100),  params.llmModelUsed ?? null)
   142→    .input('timestamp',      sql.DateTime,       new Date())
   143→    .query(`
   144→      INSERT INTO Messages (conversationId, role, content, llmModelUsed, timestamp)
   145→      VALUES (@conversationId, @role, @content, @llmModelUsed, @timestamp)
   146→    `);
   147→}
   148→
   149→/** Haalt de berichtgeschiedenis van een conversatie op. */
   150→export async function getConversationMessages(conversationId: string) {
   151→  const pool = await getPool();
   152→  const result = await pool.request()
   153→    .input('conversationId', sql.NVarChar(100), conversationId)
   154→    .query(`
   155→      SELECT messageId, role, content, timestamp, llmModelUsed
   156→      FROM   Messages
   157→      WHERE  conversationId = @conversationId
   158→      ORDER  BY timestamp ASC
   159→    `);
