 * types/index.ts
 * Gedeelde TypeScript type-definities voor het hele project.
 */

export interface Vehicle {
  id: number;
  brand: string;
  model: string;
  type: 'sedan' | 'suv' | 'hatchback' | 'van' | 'electric' | 'convertible' | 'truck';
  seats: number;
  engineCC: number | null;
  dailyPrice: number;
  availabilityStatus: 'available' | 'rented' | 'maintenance';
  locationId: number | null;
  locationName?: string;
  locationCity?: string;
  lastUpdated: string;
}

export interface RentalLocation {
  id: number;
  name: string;
  city: string;
  address: string;
  phone: string;
  email: string;
  isActive: boolean;
}

