/**
 * lib/llm.ts
 * LM Studio helpers: dynamische system-prompt opbouw + streaming LLM-aanroepen.
 * De system-prompt wordt per request opnieuw gebouwd met live DB-data,
 * zodat prijs en beschikbaarheid altijd actueel zijn.
 */

import { getVehicles, getLocations, logVehicleQuery } from './db';

export interface ChatMessage {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

// ---------------------------------------------------------------
// System-prompt builder (dynamisch, op basis van live DB-data)
// ---------------------------------------------------------------

/**
 * Bouwt de volledige system-prompt op met actuele voertuigdata en locaties.
 * Wordt bij elke chat-aanroep opnieuw uitgevoerd → altijd live data.
 *
 * @param conversationId - voor analytics logging
 */
export async function buildSystemPrompt(conversationId: string): Promise<string> {
  const [vehicles, locations] = await Promise.all([getVehicles(), getLocations()]);

  // Log voor analytics (fire-and-forget)
  logVehicleQuery({
    conversationId,
    queryType: 'general',
    response:  `${vehicles.length} voertuigen, ${locations.length} locaties geladen`,
  }).catch(() => {/* niet-kritiek */});

  // Formatteer voertuigen als leesbare lijst
  const vehicleLines = vehicles
    .map(v => {
      const statusIcon =
        v.availabilityStatus === 'available'   ? '✅ BESCHIKBAAR' :
        v.availabilityStatus === 'maintenance' ? '🔧 IN ONDERHOUD' :
                                                 '❌ VERHUURD';
      const motor = v.engineCC ? `${v.engineCC}cc` : 'Elektrisch';
      const locatieInfo = v.locationCity
        ? ` | Vestiging: ${v.locationCity}`
        : '';
      return `• ${v.brand} ${v.model} (${v.type}) — €${Number(v.dailyPrice).toFixed(2)}/dag | ${statusIcon} | ${v.seats} zitpl. | ${motor}${locatieInfo}`;
    })
    .join('\n');

  // Formatteer locaties
  const locationLines = locations
    .map(l => `• ${l.name} — ${l.address} | ☎ ${l.phone}`)
    .join('\n');

  const tijdstip = new Date().toLocaleString('nl-BE', { timeZone: 'Europe/Brussels' });

  return `\
Je bent een vriendelijke en professionele digitale medewerker van **PeterAllesweter Autoverhuur** — een gerenommeerd autoverhuurbedrijf met 15 vestigingen in heel België.

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
🚗 ACTUELE VLOOTDATA (live update: ${tijdstip})
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
${vehicleLines || '(Geen voertuigen beschikbaar)'}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📍 ONZE VESTIGINGEN (${locations.length} locaties)
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
${locationLines || '(Geen locaties beschikbaar)'}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
📋 VERHUURBELEID
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
• Minimumleeftijd: 21 jaar (25 jaar voor premium/sportvoertuigen)
• Rijbewijs B vereist (minimaal 2 jaar in bezit)
• Basisverzekering (BA + mini-casco) altijd inbegrepen
• Brandstofbeleid: vol-om-vol
• Gratis annulering tot 48 uur voor aanvang
• Last-minute (< 24 uur): prijstoeslag tot 15% mogelijk
• Verhuurperiode > 7 dagen: kortingen beschikbaar op aanvraag
• Kilometrage: onbeperkt (tenzij contractueel anders)

🎁 BESCHIKBARE EXTRA'S (prijs op aanvraag):
• GPS-navigatie | Kinderzitje (baby/peuter/junior) | Extra bestuurder
• Premium verzekering (€0 eigen risico) | Winterbandenpakket | Ski-drager

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
💡 GEDRAGSREGELS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
1. Beantwoord ALTIJD in het Nederlands (of de taal van de klant als die anders schrijft).
2. Gebruik de bovenstaande live-data voor prijs en beschikbaarheid — geef NOOIT verouderde info.
3. Is een voertuig niet beschikbaar? Stel onmiddellijk een vergelijkbaar alternatief voor.
4. Voor definitieve reserveringen: verwijs naar onze website of mail ${process.env.CONTACT_EMAIL || 'info@peterallesweter.be'}.
5. Spreek klanten aan met "u". Wees warm, professioneel en bondig.
6. Weet je iets niet zeker? Zeg dat eerlijk en bied aan het te laten nakijken.`;
}

// ---------------------------------------------------------------
// Streaming LLM-aanroep (voor SSE in de chat-API)
// ---------------------------------------------------------------

/**
 * Maakt een streaming aanroep naar LM Studio.
 * Retourneert een ReadableStream van SSE-events.
 * Elke data-chunk bevat { token: string } of [DONE] of { error: string }.
 */
export async function streamLLMResponse(
  messages: ChatMessage[],
  signal?: AbortSignal
): Promise<ReadableStream<Uint8Array>> {
  const llmUrl   = process.env.LLM_URL   || 'http://localhost:1234/v1/chat/completions';
  const llmModel = process.env.LLM_MODEL || 'local-model';
  const timeout  = Number(process.env.LLM_TIMEOUT ?? 30_000);
  const encoder  = new TextEncoder();

  return new ReadableStream({
    async start(controller) {
      const emit = (data: unknown) =>
        controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));

      try {
        const llmRes = await fetch(llmUrl, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            model: llmModel,
            messages,
            stream:      true,
            temperature: 0.7,
            max_tokens:  1024,
          }),
          signal: signal ?? AbortSignal.timeout(timeout),
        });

        if (!llmRes.ok) throw new Error(`LLM ${llmRes.status}: ${llmRes.statusText}`);

        const reader  = llmRes.body?.getReader();
        if (!reader) throw new Error('Geen response body ontvangen van LLM');

        const decoder = new TextDecoder();

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          for (const line of decoder.decode(value, { stream: true }).split('\n')) {
            if (!line.startsWith('data: ')) continue;
            const raw = line.slice(6).trim();
            if (raw === '[DONE]') {
              controller.enqueue(encoder.encode('data: [DONE]\n\n'));
              controller.close();
              return;
            }
            try {
              const token: string = JSON.parse(raw)?.choices?.[0]?.delta?.content ?? '';
              if (token) emit({ token });
            } catch { /* ongeldige chunk → overslaan */ }
          }
        }

        controller.enqueue(encoder.encode('data: [DONE]\n\n'));
        controller.close();
      } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        console.error('[LLM] Streaming fout:', msg);
        emit({ error: msg });
        controller.close();
      }
    },
  });
}

