 * PUT    — admin vereist
 * DELETE — admin vereist
 */

import { NextRequest, NextResponse } from 'next/server';
import { getPool, sql }              from '@/lib/db';
import { getUser }                   from '@/lib/auth';

/** GET /api/vehicles — alle voertuigen met joins */
export async function GET() {
  try {
    const pool   = await getPool();
    const result = await pool.request().query(`
      SELECT
        v.id, v.brand, v.model, v.type, v.licensePlate, v.year,
        v.seats, v.engineTypeId, v.engineCC, v.powerKW,
        v.transmissionType, v.availabilityStatus,
        v.locationId, v.mileage, v.lastUpdated, v.notes,
        e.name        AS engineTypeName,
        e.fuelType,
        e.co2Category,
        l.name        AS locationName,
        l.city        AS locationCity,
        p.halfDayPrice, p.fullDayPrice, p.weekendPrice, p.weekPrice, p.monthPrice
      FROM Vehicles v
      LEFT JOIN EngineTypes     e ON v.engineTypeId = e.id
      LEFT JOIN RentalLocations l ON v.locationId   = l.id
      LEFT JOIN VehiclePricing  p ON v.id           = p.vehicleId
                                  AND p.validUntil IS NULL
      ORDER BY v.brand, v.model
    `);
    return NextResponse.json(result.recordset);
  } catch (err) {
    console.error('[Vehicles] GET mislukt:', err);
    return NextResponse.json({ error: 'Database-fout.' }, { status: 500 });
  }
}

/** POST /api/vehicles — nieuw voertuig + prijs aanmaken */
export async function POST(request: NextRequest) {
  const user = await getUser();
  if (user?.role !== 'admin')
    return NextResponse.json({ error: 'Niet geautoriseerd.' }, { status: 403 });

  try {
    const b = await request.json();
    if (!b.brand || !b.model || !b.type || !b.licensePlate || !b.engineTypeId || !b.locationId)
      return NextResponse.json(
        { error: 'brand, model, type, licensePlate, engineTypeId en locationId zijn verplicht.' },
        { status: 400 }
      );

    const pool   = await getPool();
    const result = await pool.request()
      .input('brand',              sql.NVarChar(100), b.brand.trim())
      .input('model',              sql.NVarChar(100), b.model.trim())
      .input('type',               sql.NVarChar(50),  b.type)
      .input('licensePlate',       sql.NVarChar(20),  b.licensePlate.trim().toUpperCase())
      .input('year',               sql.Int,           b.year          ?? new Date().getFullYear())
      .input('seats',              sql.Int,           b.seats         ?? 5)
      .input('engineTypeId',       sql.Int,           b.engineTypeId)
      .input('engineCC',           sql.Int,           b.engineCC      ?? null)
      .input('powerKW',            sql.Int,           b.powerKW       ?? null)
      .input('transmissionType',   sql.NVarChar(20),  b.transmissionType ?? 'automatic')
      .input('availabilityStatus', sql.NVarChar(20),  b.availabilityStatus ?? 'available')
      .input('locationId',         sql.Int,           b.locationId)
      .input('mileage',            sql.Int,           b.mileage       ?? 0)
      .input('notes',              sql.NVarChar(500), b.notes         ?? null)
      .input('lastUpdated',        sql.DateTime,      new Date())
      .query(`
        INSERT INTO Vehicles
          (brand, model, type, licensePlate, year, seats, engineTypeId,
           engineCC, powerKW, transmissionType, availabilityStatus,
           locationId, mileage, notes, lastUpdated)
        OUTPUT INSERTED.*
        VALUES
          (@brand, @model, @type, @licensePlate, @year, @seats, @engineTypeId,
           @engineCC, @powerKW, @transmissionType, @availabilityStatus,
           @locationId, @mileage, @notes, @lastUpdated)
      `);

    const vehicle = result.recordset[0];

    // Prijs aanmaken indien meegegeven
    if (b.halfDayPrice != null) {
      await pool.request()
        .input('vehicleId',    sql.Int,           vehicle.id)
        .input('halfDayPrice', sql.Decimal(10,2), parseFloat(b.halfDayPrice))
        .input('fullDayPrice', sql.Decimal(10,2), parseFloat(b.fullDayPrice  ?? b.halfDayPrice * 1.8))
        .input('weekendPrice', sql.Decimal(10,2), parseFloat(b.weekendPrice  ?? b.halfDayPrice * 4))
        .input('weekPrice',    sql.Decimal(10,2), parseFloat(b.weekPrice     ?? b.halfDayPrice * 10))
        .input('monthPrice',   sql.Decimal(10,2), parseFloat(b.monthPrice    ?? b.halfDayPrice * 30))
        .input('validFrom',    sql.Date,          new Date())
        .query(`
          INSERT INTO VehiclePricing
            (vehicleId, halfDayPrice, fullDayPrice, weekendPrice, weekPrice, monthPrice, validFrom)
          VALUES
            (@vehicleId, @halfDayPrice, @fullDayPrice, @weekendPrice, @weekPrice, @monthPrice, @validFrom)
        `);
    }

    return NextResponse.json(vehicle, { status: 201 });
  } catch (err) {
    console.error('[Vehicles] POST mislukt:', err);
    return NextResponse.json({ error: 'Database-fout.' }, { status: 500 });
  }
}

