/**
 * app/admin/page.tsx
 * Admin-beheerpagina: CRUD voor Voertuigen, Locaties en Gesprekken.
 * Alleen toegankelijk voor gebruikers met rol 'admin' (afgedwongen in middleware).
 */
'use client';

import { useState, useEffect, useCallback } from 'react';
import { Plus, Pencil, Trash2, X, Check, RefreshCw, MessageSquare, ChevronDown, ChevronUp } from 'lucide-react';
import { Button }  from '@/components/ui/button';
import { Input }   from '@/components/ui/input';
import { Badge }   from '@/components/ui/badge';
import type { Vehicle, RentalLocation, Conversation, Message } from '@/types';

// ─── Tabs ────────────────────────────────────────────────────────────────────
type Tab = 'vehicles' | 'locations' | 'conversations';

// ─── Leeg voertuig-object voor "Nieuw voertuig" formulier ────────────────────
const emptyVehicle = (): Partial<Vehicle> => ({
  brand: '', model: '', type: 'sedan', seats: 5,
  engineCC: undefined, dailyPrice: 0,
  availabilityStatus: 'available', locationId: undefined,
});

const emptyLocation = (): Partial<RentalLocation> => ({
  name: '', city: '', address: '', phone: '', email: '', isActive: true,
});

export default function AdminPage() {
  const [tab, setTab] = useState<Tab>('vehicles');

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <div className="bg-white border-b border-gray-200 px-6 py-4">
        <h1 className="text-xl font-bold text-gray-900">Beheerpaneel</h1>
        <p className="text-sm text-gray-500">PeterAllesweter Autoverhuur — Administratie</p>
      </div>

      {/* Tabs */}
      <div className="border-b border-gray-200 bg-white px-6">
        <div className="flex gap-1">
          {(['vehicles', 'locations', 'conversations'] as Tab[]).map(t => (
            <button
              key={t}
              onClick={() => setTab(t)}
              className={`px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
                tab === t
                  ? 'border-brand-600 text-brand-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              {t === 'vehicles' ? '🚗 Voertuigen'
               : t === 'locations' ? '📍 Locaties'
               : '💬 Gesprekken'}
            </button>
          ))}
        </div>
      </div>

      <div className="p-6">
        {tab === 'vehicles'      && <VehiclesTab />}
        {tab === 'locations'     && <LocationsTab />}
        {tab === 'conversations' && <ConversationsTab />}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Voertuigen tab
// ─────────────────────────────────────────────────────────────────────────────
function VehiclesTab() {
  const [vehicles,  setVehicles]  = useState<Vehicle[]>([]);
  const [locations, setLocations] = useState<RentalLocation[]>([]);
  const [loading,   setLoading]   = useState(true);
  const [editing,   setEditing]   = useState<Partial<Vehicle> | null>(null);
  const [isNew,     setIsNew]     = useState(false);
  const [saving,    setSaving]    = useState(false);
  const [error,     setError]     = useState('');

  const load = useCallback(async () => {
    setLoading(true);
    const [vRes, lRes] = await Promise.all([
      fetch('/api/vehicles'),
      fetch('/api/locations'),
    ]);
    setVehicles(await vRes.json());
    setLocations(await lRes.json());
    setLoading(false);
  }, []);

  useEffect(() => { load(); }, [load]);

  const startNew  = () => { setEditing(emptyVehicle()); setIsNew(true);  setError(''); };
  const startEdit = (v: Vehicle) => { setEditing({ ...v }); setIsNew(false); setError(''); };
  const cancel    = () => { setEditing(null); setError(''); };

  const save = async () => {
    if (!editing) return;
    setSaving(true); setError('');
    try {
      const res = await fetch('/api/vehicles', {
        method:  isNew ? 'POST' : 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify(editing),
      });
      if (!res.ok) { const d = await res.json(); setError(d.error); }
      else { setEditing(null); load(); }
    } catch { setError('Netwerkfout.'); }
    setSaving(false);
  };

  const remove = async (id: number) => {
    if (!confirm('Voertuig definitief verwijderen?')) return;
    await fetch(`/api/vehicles?id=${id}`, { method: 'DELETE' });
    load();
  };

  const STATUS_OPTIONS = ['available', 'rented', 'maintenance'];
  const TYPE_OPTIONS   = ['sedan','suv','hatchback','van','electric','convertible','truck'];

  return (
    <div>
      <div className="mb-4 flex items-center justify-between">
        <h2 className="font-semibold text-gray-900">Voertuigen ({vehicles.length})</h2>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={load}><RefreshCw size={14} /> Vernieuwen</Button>
          <Button size="sm" onClick={startNew}><Plus size={14} /> Nieuw voertuig</Button>
        </div>
      </div>

      {/* Formulier (inline edit/new) */}
      {editing && (
        <div className="mb-6 rounded-xl border border-brand-200 bg-brand-50 p-5">
          <h3 className="mb-4 font-medium text-brand-900">{isNew ? 'Nieuw voertuig' : 'Voertuig bewerken'}</h3>
          {error && <p className="mb-3 text-sm text-red-600">{error}</p>}
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3">
            <Field label="Merk*">
              <Input value={editing.brand ?? ''} onChange={e => setEditing(p => ({ ...p, brand: e.target.value }))} placeholder="bijv. Volkswagen" />
            </Field>
            <Field label="Model*">
              <Input value={editing.model ?? ''} onChange={e => setEditing(p => ({ ...p, model: e.target.value }))} placeholder="bijv. Golf" />
            </Field>
            <Field label="Type*">
              <select className="h-10 w-full rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-brand-600"
                value={editing.type ?? 'sedan'}
                onChange={e => setEditing(p => ({ ...p, type: e.target.value as Vehicle['type'] }))}>
                {TYPE_OPTIONS.map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </Field>
            <Field label="Zitplaatsen">
              <Input type="number" min={1} max={50} value={editing.seats ?? 5} onChange={e => setEditing(p => ({ ...p, seats: +e.target.value }))} />
            </Field>
            <Field label="Motor (cc, leeg=elektrisch)">
              <Input type="number" value={editing.engineCC ?? ''} onChange={e => setEditing(p => ({ ...p, engineCC: e.target.value ? +e.target.value : undefined }))} placeholder="bijv. 1598" />
            </Field>
            <Field label="Prijs/dag (€)*">
              <Input type="number" min={0} step={0.01} value={editing.dailyPrice ?? 0} onChange={e => setEditing(p => ({ ...p, dailyPrice: +e.target.value }))} />
            </Field>
            <Field label="Status">
              <select className="h-10 w-full rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-brand-600"
                value={editing.availabilityStatus ?? 'available'}
                onChange={e => setEditing(p => ({ ...p, availabilityStatus: e.target.value as Vehicle['availabilityStatus'] }))}>
                {STATUS_OPTIONS.map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </Field>
            <Field label="Locatie">
              <select className="h-10 w-full rounded-lg border border-gray-300 bg-white px-3 text-sm focus:outline-none focus:ring-2 focus:ring-brand-600"
                value={editing.locationId ?? ''}
                onChange={e => setEditing(p => ({ ...p, locationId: e.target.value ? +e.target.value : undefined }))}>
                <option value="">— geen locatie —</option>
                {locations.map(l => <option key={l.id} value={l.id}>{l.city} — {l.name}</option>)}
              </select>
            </Field>
          </div>
          <div className="mt-4 flex gap-2">
            <Button onClick={save} disabled={saving} size="sm">
              <Check size={14} /> {saving ? 'Opslaan…' : 'Opslaan'}
            </Button>
            <Button variant="outline" size="sm" onClick={cancel}><X size={14} /> Annuleren</Button>
          </div>
        </div>
      )}

      {/* Tabel */}
      {loading ? <p className="text-sm text-gray-500">Laden…</p> : (
        <div className="overflow-x-auto rounded-xl border border-gray-200 bg-white">
          <table className="w-full text-sm">
            <thead className="border-b border-gray-200 bg-gray-50">
              <tr>
                {['#','Merk','Model','Type','Zitpl.','CC','€/dag','Status','Locatie',''].map(h => (
                  <th key={h} className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wide">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {vehicles.map(v => (
                <tr key={v.id} className="hover:bg-gray-50">
                  <td className="px-4 py-3 text-gray-400">{v.id}</td>
                  <td className="px-4 py-3 font-medium">{v.brand}</td>
                  <td className="px-4 py-3">{v.model}</td>
                  <td className="px-4 py-3 text-gray-500">{v.type}</td>
                  <td className="px-4 py-3">{v.seats}</td>
                  <td className="px-4 py-3">{v.engineCC ?? '⚡'}</td>
                  <td className="px-4 py-3 font-semibold text-brand-700">€{Number(v.dailyPrice).toFixed(0)}</td>
                  <td className="px-4 py-3">
                    <Badge variant={v.availabilityStatus as 'available' | 'rented' | 'maintenance'}>
                      {v.availabilityStatus}
                    </Badge>
                  </td>
                  <td className="px-4 py-3 text-gray-500">{v.locationCity ?? '—'}</td>
                  <td className="px-4 py-3">
                    <div className="flex gap-1">
                      <Button variant="ghost" size="icon" onClick={() => startEdit(v)}><Pencil size={14} /></Button>
                      <Button variant="ghost" size="icon" onClick={() => remove(v.id)} className="text-red-500 hover:text-red-700"><Trash2 size={14} /></Button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Locaties tab
// ─────────────────────────────────────────────────────────────────────────────
function LocationsTab() {
  const [locations, setLocations] = useState<RentalLocation[]>([]);
  const [loading,   setLoading]   = useState(true);
  const [editing,   setEditing]   = useState<Partial<RentalLocation> | null>(null);
  const [isNew,     setIsNew]     = useState(false);
  const [saving,    setSaving]    = useState(false);
  const [error,     setError]     = useState('');

  const load = useCallback(async () => {
    setLoading(true);
    const res = await fetch('/api/locations');
    setLocations(await res.json());
    setLoading(false);
  }, []);

  useEffect(() => { load(); }, [load]);

  const startNew  = () => { setEditing(emptyLocation()); setIsNew(true); setError(''); };
  const startEdit = (l: RentalLocation) => { setEditing({ ...l }); setIsNew(false); setError(''); };
  const cancel    = () => { setEditing(null); setError(''); };

  const save = async () => {
    if (!editing) return;
    setSaving(true); setError('');
    try {
      const res = await fetch('/api/locations', {
        method:  isNew ? 'POST' : 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify(editing),
      });
      if (!res.ok) { const d = await res.json(); setError(d.error); }
      else { setEditing(null); load(); }
    } catch { setError('Netwerkfout.'); }
    setSaving(false);
  };

  const remove = async (id: number) => {
    if (!confirm('Locatie deactiveren?')) return;
    await fetch(`/api/locations?id=${id}`, { method: 'DELETE' });
    load();
  };

  return (
    <div>
      <div className="mb-4 flex items-center justify-between">
        <h2 className="font-semibold text-gray-900">Verhuurlocaties ({locations.length})</h2>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={load}><RefreshCw size={14} /> Vernieuwen</Button>
          <Button size="sm" onClick={startNew}><Plus size={14} /> Nieuwe locatie</Button>
        </div>
      </div>

      {editing && (
        <div className="mb-6 rounded-xl border border-brand-200 bg-brand-50 p-5">
          <h3 className="mb-4 font-medium text-brand-900">{isNew ? 'Nieuwe locatie' : 'Locatie bewerken'}</h3>
          {error && <p className="mb-3 text-sm text-red-600">{error}</p>}
          <div className="grid gap-3 sm:grid-cols-2">
            <Field label="Naam*"><Input value={editing.name ?? ''} onChange={e => setEditing(p => ({ ...p, name: e.target.value }))} placeholder="bijv. PeterAllesweter Gent" /></Field>
            <Field label="Stad*"><Input value={editing.city ?? ''} onChange={e => setEditing(p => ({ ...p, city: e.target.value }))} placeholder="bijv. Gent" /></Field>
            <Field label="Adres*"><Input value={editing.address ?? ''} onChange={e => setEditing(p => ({ ...p, address: e.target.value }))} placeholder="bijv. Korenmarkt 8, 9000 Gent" /></Field>
            <Field label="Telefoon*"><Input value={editing.phone ?? ''} onChange={e => setEditing(p => ({ ...p, phone: e.target.value }))} placeholder="+32 9 123 45 67" /></Field>
            <Field label="E-mail*"><Input type="email" value={editing.email ?? ''} onChange={e => setEditing(p => ({ ...p, email: e.target.value }))} placeholder="gent@peterallesweter.be" /></Field>
            <Field label="Actief">
              <label className="flex items-center gap-2 mt-2 cursor-pointer">
                <input type="checkbox" checked={editing.isActive ?? true} onChange={e => setEditing(p => ({ ...p, isActive: e.target.checked }))} className="h-4 w-4 rounded border-gray-300 accent-brand-600" />
                <span className="text-sm text-gray-700">Locatie is actief</span>
              </label>
            </Field>
          </div>
          <div className="mt-4 flex gap-2">
            <Button onClick={save} disabled={saving} size="sm"><Check size={14} /> {saving ? 'Opslaan…' : 'Opslaan'}</Button>
            <Button variant="outline" size="sm" onClick={cancel}><X size={14} /> Annuleren</Button>
          </div>
        </div>
      )}

      {loading ? <p className="text-sm text-gray-500">Laden…</p> : (
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
          {locations.map(l => (
            <div key={l.id} className="rounded-xl border border-gray-200 bg-white p-4 shadow-sm">
              <div className="flex items-start justify-between">
                <div>
                  <p className="font-medium text-gray-900 text-sm">{l.name}</p>
                  <p className="text-xs text-gray-500 mt-0.5">{l.city}</p>
                </div>
                <Badge variant={l.isActive ? 'available' : 'rented'}>{l.isActive ? 'Actief' : 'Inactief'}</Badge>
              </div>
              <p className="mt-2 text-xs text-gray-600">{l.address}</p>
              <p className="mt-1 text-xs text-gray-500">{l.phone}</p>
              <div className="mt-3 flex gap-1 justify-end">
                <Button variant="ghost" size="icon" onClick={() => startEdit(l)}><Pencil size={13} /></Button>
                <Button variant="ghost" size="icon" onClick={() => remove(l.id)} className="text-red-500"><Trash2 size={13} /></Button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Gesprekken tab
// ─────────────────────────────────────────────────────────────────────────────
function ConversationsTab() {
