                    </p>
                  </div>
                </div>
                {expanded === c.conversationId ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
              </button>

              {expanded === c.conversationId && (
                <div className="border-t border-gray-100 p-4 space-y-2 max-h-80 overflow-y-auto bg-gray-50">
