            <p className="font-semibold text-gray-900 leading-tight">
              {vehicle.brand} {vehicle.model}
            </p>
            <p className="text-xs text-gray-500 mt-0.5">{TYPE_LABEL[vehicle.type] ?? vehicle.type}</p>
          </div>
          <Badge variant={statusVariant as 'available' | 'rented' | 'maintenance'}>
            {STATUS_LABEL[vehicle.availabilityStatus]}
          </Badge>
