/**
 * components/Navbar.tsx
 * Navigatiebalk met logo, links en gebruikersmenu.
 */
'use client';

import { useState }        from 'react';
import Link                from 'next/link';
import { useRouter }       from 'next/navigation';
import { Car, LogOut, Settings, Menu, X } from 'lucide-react';
import { Button }          from './ui/button';
import type { AuthUser }   from '@/types';

interface Props {
  user: AuthUser | null;
}

export function Navbar({ user }: Props) {
  const router     = useRouter();
  const [open, setOpen] = useState(false);

  const logout = async () => {
    await fetch('/api/auth', { method: 'DELETE' });
    router.push('/login');
    router.refresh();
  };

  return (
    <nav className="sticky top-0 z-50 border-b border-gray-200 bg-white shadow-sm">
      <div className="mx-auto flex max-w-7xl items-center justify-between px-4 py-3">
        {/* Logo */}
        <Link href="/" className="flex items-center gap-2 font-bold text-brand-700 text-lg">
          <Car className="h-6 w-6" />
          <span>PeterAllesweter</span>
        </Link>

        {/* Desktop nav */}
        <div className="hidden md:flex items-center gap-4">
          {user ? (
            <>
              <span className="text-sm text-gray-600">
                {user.email}
                {user.role === 'admin' && (
                  <span className="ml-2 rounded-full bg-brand-100 px-2 py-0.5 text-xs font-medium text-brand-700">
                    Admin
                  </span>
                )}
              </span>
              {user.role === 'admin' && (
                <Link href="/admin">
                  <Button variant="outline" size="sm">
                    <Settings size={14} />
                    Beheer
                  </Button>
                </Link>
              )}
              <Button variant="ghost" size="sm" onClick={logout}>
                <LogOut size={14} />
                Uitloggen
              </Button>
            </>
          ) : (
            <Link href="/login">
              <Button size="sm">Inloggen</Button>
            </Link>
          )}
        </div>

        {/* Mobiel menu-knop */}
        <button
          className="md:hidden p-1 text-gray-600"
          onClick={() => setOpen(!open)}
          aria-label="Menu"
        >
          {open ? <X size={22} /> : <Menu size={22} />}
        </button>
      </div>

      {/* Mobiel dropdown */}
      {open && (
        <div className="md:hidden border-t border-gray-200 bg-white px-4 py-3 space-y-2">
          {user ? (
            <>
              <p className="text-sm text-gray-600">{user.email}</p>
              {user.role === 'admin' && (
                <Link href="/admin" onClick={() => setOpen(false)}>
                  <Button variant="outline" size="sm" className="w-full">
                    Beheer
                  </Button>
                </Link>
              )}
              <Button variant="ghost" size="sm" className="w-full" onClick={logout}>
                Uitloggen
              </Button>
            </>
          ) : (
            <Link href="/login" onClick={() => setOpen(false)}>
              <Button size="sm" className="w-full">Inloggen</Button>
            </Link>
          )}
        </div>
      )}
    </nav>
  );
}

