/**
 * app/login/page.tsx
 * Inlogpagina met e-mail + wachtwoord formulier.
 */
'use client';

import { useState, FormEvent } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Car, Loader2 }        from 'lucide-react';
import { Button }              from '@/components/ui/button';
import { Input }               from '@/components/ui/input';

export default function LoginPage() {
  const router      = useRouter();
  const params      = useSearchParams();
  const redirect    = params.get('redirect') ?? '/';
  const errorParam  = params.get('error');

  const [email,    setEmail]    = useState('');
  const [password, setPassword] = useState('');
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState(
    errorParam === 'unauthorized' ? 'U heeft geen toegang tot deze pagina.' : ''
  );

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const res  = await fetch('/api/auth', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ email: email.trim(), password }),
      });

      const data = await res.json();

      if (!res.ok) {
        setError(data.error ?? 'Inloggen mislukt.');
      } else {
        router.push(redirect);
        router.refresh();
      }
    } catch {
      setError('Netwerkfout. Probeer opnieuw.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-gradient-to-br from-brand-50 to-gray-100 px-4">
      <div className="w-full max-w-sm">
        {/* Logo */}
        <div className="mb-8 text-center">
          <div className="mx-auto mb-4 flex h-14 w-14 items-center justify-center rounded-2xl bg-brand-600 text-white">
            <Car size={28} />
          </div>
          <h1 className="text-2xl font-bold text-gray-900">PeterAllesweter</h1>
          <p className="mt-1 text-sm text-gray-500">Autoverhuur Beheerportaal</p>
        </div>

        {/* Formulier */}
        <div className="rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
          <h2 className="mb-5 text-base font-semibold text-gray-900">Inloggen</h2>

          {error && (
            <div className="mb-4 rounded-lg bg-red-50 px-4 py-3 text-sm text-red-700 border border-red-200">
              {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="mb-1.5 block text-sm font-medium text-gray-700">
                E-mailadres
              </label>
              <Input
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="uw@email.be"
                required
                autoComplete="email"
                disabled={loading}
              />
            </div>

            <div>
              <label className="mb-1.5 block text-sm font-medium text-gray-700">
                Wachtwoord
              </label>
              <Input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="••••••••"
                required
                autoComplete="current-password"
                disabled={loading}
              />
            </div>

            <Button type="submit" className="w-full" disabled={loading}>
              {loading && <Loader2 size={16} className="animate-spin" />}
              {loading ? 'Inloggen…' : 'Inloggen'}
            </Button>
          </form>

          {/* Demo credentials info */}
          <div className="mt-5 rounded-lg bg-gray-50 p-3 text-xs text-gray-500 space-y-1 border border-gray-200">
            <p className="font-medium text-gray-600">Demo-accounts:</p>
            <p>👤 demo@peterallesweter.be / Demo2026!</p>
            <p>🔑 admin@peterallesweter.be / Admin2026!</p>
          </div>
        </div>
      </div>
    </div>
  );
}

