/**
 * components/Navbar.tsx
 * Navigatiebalk in Dockx-stijl: groene achtergrond (#007c30), geel accent.
 */
'use client';

import { useState }      from 'react';
import Link              from 'next/link';
import { useRouter }     from 'next/navigation';
import { Car, LogOut, Settings, Menu, X } from 'lucide-react';
import type { AuthUser } from '@/types';

interface Props {
  user: AuthUser | null;
}

export function Navbar({ user }: Props) {
  const router          = useRouter();
  const [open, setOpen] = useState(false);

  const logout = async () => {
    await fetch('/api/auth', { method: 'DELETE' });
    router.push('/login');
    router.refresh();
  };

  return (
    <nav className="sticky top-0 z-50 bg-brand-600 shadow-md">
      <div className="mx-auto flex max-w-7xl items-center justify-between px-4 py-3">

        {/* Logo */}
        <Link href="/" className="flex items-center gap-2 text-lg font-bold text-white hover:text-accent transition-colors">
          <Car className="h-6 w-6" />
          <span>PeterAllesweter</span>
        </Link>

        {/* Desktop nav */}
        <div className="hidden md:flex items-center gap-3">
          {user ? (
            <>
              <span className="text-sm text-green-100">
                {user.email}
                {user.role === 'admin' && (
                  <span className="ml-2 rounded-full bg-accent px-2 py-0.5 text-xs font-semibold text-brand-900">
                    Admin
                  </span>
                )}
              </span>
              {user.role === 'admin' && (
                <Link href="/admin">
                  <button className="flex items-center gap-1.5 rounded-lg border border-white/30 bg-white/10 px-3 py-1.5 text-xs font-medium text-white hover:bg-white/20 transition-colors">
                    <Settings size={13} />
                    Beheer
                  </button>
                </Link>
              )}
              <button
                onClick={logout}
                className="flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-xs font-medium text-green-100 hover:bg-white/10 transition-colors"
              >
                <LogOut size={13} />
                Uitloggen
              </button>
            </>
          ) : (
            <Link href="/login">
              <button className="rounded-lg bg-accent px-4 py-2 text-sm font-semibold text-brand-900 hover:bg-accent-hover transition-colors">
                Inloggen
              </button>
            </Link>
          )}
        </div>

        {/* Mobiel menu-knop */}
        <button
