/**
 * app/login/page.tsx
 * Inlogpagina — Dockx-stijl: groene achtergrond, geel accent.
 */
'use client';

import { useState, FormEvent }          from 'react';
import { useRouter, useSearchParams }   from 'next/navigation';
import { Car, Loader2 }                 from 'lucide-react';
import { Button }                       from '@/components/ui/button';
import { Input }                        from '@/components/ui/input';

export default function LoginPage() {
  const router     = useRouter();
  const params     = useSearchParams();
  const redirect   = params.get('redirect') ?? '/';
  const errorParam = params.get('error');

  const [email,    setEmail]    = useState('');
  const [password, setPassword] = useState('');
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState(
    errorParam === 'unauthorized' ? 'U heeft geen toegang tot deze pagina.' : ''
  );

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const res  = await fetch('/api/auth', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ email: email.trim(), password }),
      });
      const data = await res.json();
      if (!res.ok) { setError(data.error ?? 'Inloggen mislukt.'); }
      else { router.push(redirect); router.refresh(); }
    } catch {
      setError('Netwerkfout. Probeer opnieuw.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center px-4"
         style={{ background: 'linear-gradient(135deg, #003012 0%, #007c30 60%, #026c3d 100%)' }}>
      <div className="w-full max-w-sm">

        {/* Logo */}
        <div className="mb-8 text-center">
          <div className="mx-auto mb-4 flex h-16 w-16 items-center justify-center rounded-2xl bg-accent shadow-lg">
            <Car size={30} className="text-brand-900" />
          </div>
          <h1 className="text-2xl font-bold text-white">PeterAllesweter</h1>
          <p className="mt-1 text-sm text-green-300">Autoverhuur Beheerportaal</p>
        </div>

        {/* Formulierkaart */}
        <div className="rounded-2xl border border-white/10 bg-white p-6 shadow-xl">
          <h2 className="mb-5 text-base font-semibold text-[#494949]">Inloggen</h2>

          {error && (
            <div className="mb-4 rounded-lg bg-red-50 px-4 py-3 text-sm text-red-700 border border-red-200">
              {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">
            <div>
              <label className="mb-1.5 block text-sm font-medium text-[#494949]">
                E-mailadres
              </label>
              <Input
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="uw@email.be"
                required
                autoComplete="email"
                disabled={loading}
              />
            </div>

            <div>
              <label className="mb-1.5 block text-sm font-medium text-[#494949]">
                Wachtwoord
              </label>
              <Input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="••••••••"
                required
                autoComplete="current-password"
                disabled={loading}
              />
            </div>

            {/* Gele CTA-knop à la Dockx */}
            <button
              type="submit"
              disabled={loading}
              className="w-full rounded-lg bg-accent py-2.5 text-sm font-semibold text-brand-900 hover:bg-accent-hover transition-colors disabled:opacity-50 disabled:pointer-events-none flex items-center justify-center gap-2"
            >
              {loading && <Loader2 size={16} className="animate-spin" />}
              {loading ? 'Inloggen…' : 'Inloggen'}
            </button>
          </form>

          {/* Demo credentials */}
          <div className="mt-5 rounded-lg p-3 text-xs space-y-1 border border-gray-200" style={{ backgroundColor: '#f3f3f3' }}>
            <p className="font-semibold text-[#494949]">Demo-accounts:</p>
            <p className="text-[#616161]">👤 demo@peterallesweter.be / Demo2026!</p>
            <p className="text-[#616161]">🔑 admin@peterallesweter.be / Admin2026!</p>
          </div>
        </div>

        <p className="mt-6 text-center text-xs text-green-400">
          © {new Date().getFullYear()} PeterAllesweter Autoverhuur
        </p>
      </div>
    </div>
  );
}

