/**
 * components/ui/button.tsx
 * Herbruikbare knopcomponent — Dockx-stijl (groen primair, geel accent).
 */
'use client';

import * as React from 'react';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '@/lib/utils';

const buttonVariants = cva(
  'inline-flex items-center justify-center gap-2 rounded-lg text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-brand-600 focus-visible:ring-offset-1 disabled:pointer-events-none disabled:opacity-50',
  {
    variants: {
      variant: {
        default:   'bg-brand-600 text-white hover:bg-brand-700',
        cta:       'bg-accent text-brand-900 font-semibold hover:bg-accent-hover',
        outline:   'border border-[#d6d6d6] bg-white text-[#494949] hover:bg-[#f3f3f3]',
        ghost:     'text-[#616161] hover:bg-[#f3f3f3] hover:text-[#494949]',
        danger:    'bg-red-600 text-white hover:bg-red-700',
        secondary: 'bg-[#f3f3f3] text-[#494949] hover:bg-[#d6d6d6]',
      },
      size: {
        sm:   'h-8  px-3 text-xs',
        md:   'h-10 px-4',
        lg:   'h-11 px-6 text-base',
        icon: 'h-9 w-9',
      },
    },
    defaultVariants: {
      variant: 'default',
      size:    'md',
    },
  }
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, ...props }, ref) => (
    <button
      className={cn(buttonVariants({ variant, size }), className)}
      ref={ref}
      {...props}
    />
  )
);
Button.displayName = 'Button';

