/**
 * components/ChatWindow.tsx
 * Volledig interactief chatvenster met SSE-streaming.
 *
 * Features:
 * - Streaming antwoorden via Server-Sent Events
 * - Automatisch scrollen naar laatste bericht
 * - Berichtgeschiedenis per sessie (conversationId)
 * - Nieuw gesprek starten
 */
'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import { Send, RefreshCw, Loader2 }                 from 'lucide-react';
import { ChatMessage }                               from './ChatMessage';
import { Button }                                    from './ui/button';
import { cn }                                        from '@/lib/utils';

interface Message {
  id:        string;
  role:      'user' | 'assistant';
  content:   string;
  timestamp: string;
  streaming?: boolean;
}

export function ChatWindow() {
  const [messages,        setMessages]        = useState<Message[]>([]);
  const [input,           setInput]           = useState('');
  const [conversationId,  setConversationId]  = useState<string>('');
  const [isLoading,       setIsLoading]       = useState(false);
  const [error,           setError]           = useState('');

  const bottomRef  = useRef<HTMLDivElement>(null);
  const inputRef   = useRef<HTMLTextAreaElement>(null);
  const abortRef   = useRef<AbortController | null>(null);

  // Scroll naar het laatste bericht
  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Welkomstbericht bij eerste render
  useEffect(() => {
    setMessages([{
      id:        'welcome',
      role:      'assistant',
      content:   'Goeiedag! Ik ben de digitale assistent van PeterAllesweter Autoverhuur. Waarmee kan ik u vandaag helpen?\n\nU kunt mij vragen stellen over:\n• Beschikbaarheid van voertuigen\n• Huurprijzen\n• Onze 15 vestigingen in België\n• Extra opties en verzekeringen',
      timestamp: new Date().toISOString(),
    }]);
  }, []);

  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text || isLoading) return;

    // Annuleer eventuele lopende aanvraag
    abortRef.current?.abort();
    abortRef.current = new AbortController();

    const userMsg: Message = {
      id:        `u_${Date.now()}`,
      role:      'user',
      content:   text,
      timestamp: new Date().toISOString(),
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setError('');
    setIsLoading(true);

    // Tijdelijk streaming-bericht aanmaken
    const botId = `b_${Date.now()}`;
    setMessages(prev => [...prev, {
      id:        botId,
      role:      'assistant',
      content:   '',
      timestamp: new Date().toISOString(),
      streaming: true,
    }]);

    try {
      const res = await fetch('/api/chat', {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ message: text, conversationId }),
        signal:  abortRef.current.signal,
      });

      const reader  = res.body?.getReader();
      if (!reader) throw new Error('Geen stream ontvangen');

      const decoder = new TextDecoder();
      let   buffer  = '';

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() ?? '';

        for (const line of lines) {
          if (!line.startsWith('data: ')) continue;
          const raw = line.slice(6).trim();

          if (raw === '[DONE]') {
            setMessages(prev =>
              prev.map(m => m.id === botId ? { ...m, streaming: false } : m)
            );
            setIsLoading(false);
            return;
          }

          try {
            const parsed = JSON.parse(raw);

            if (parsed.error) {
              setError(parsed.error);
              setMessages(prev => prev.filter(m => m.id !== botId));
              setIsLoading(false);
              return;
            }

            if (parsed.conversationId && !conversationId) {
              setConversationId(parsed.conversationId);
            }

            if (parsed.token) {
              setMessages(prev =>
                prev.map(m =>
                  m.id === botId
                    ? { ...m, content: m.content + parsed.token }
                    : m
                )
              );
            }
          } catch { /* ongeldige JSON chunk */ }
        }
      }
    } catch (err) {
      if ((err as Error).name !== 'AbortError') {
        setError('Verbindingsfout. Controleer of LM Studio actief is.');
        setMessages(prev => prev.filter(m => m.id !== botId));
      }
    } finally {
      setIsLoading(false);
    }
  }, [input, isLoading, conversationId]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const startNewConversation = () => {
    abortRef.current?.abort();
    setConversationId('');
    setMessages([{
      id:        'welcome-new',
      role:      'assistant',
      content:   'Nieuw gesprek gestart. Hoe kan ik u helpen?',
      timestamp: new Date().toISOString(),
    }]);
    setError('');
    inputRef.current?.focus();
  };

  return (
    <div className="flex h-full flex-col rounded-2xl border border-gray-200 bg-white shadow-lg overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between border-b border-gray-200 bg-brand-600 px-4 py-3">
        <div className="flex items-center gap-2">
          <div className="h-2.5 w-2.5 rounded-full bg-green-400 animate-pulse" />
          <span className="font-semibold text-white text-sm">PeterAllesweter Assistent</span>
        </div>
        <Button
          variant="ghost"
          size="icon"
          onClick={startNewConversation}
          title="Nieuw gesprek"
          className="text-white hover:bg-brand-700"
        >
          <RefreshCw size={16} />
        </Button>
      </div>

      {/* Berichten */}
      <div className="flex-1 overflow-y-auto chat-scroll py-2">
        {messages.map(msg => (
          <ChatMessage
            key={msg.id}
            role={msg.role}
            content={msg.content}
            timestamp={msg.timestamp}
            streaming={msg.streaming}
          />
        ))}

        {/* Laad-indicator: drie puntjes */}
        {isLoading && messages[messages.length - 1]?.content === '' && (
          <div className="flex gap-3 px-4 py-2">
            <div className="flex h-8 w-8 items-center justify-center rounded-full bg-gray-700 text-white">
              <Loader2 size={14} className="animate-spin" />
            </div>
          </div>
        )}

        {/* Foutmelding */}
        {error && (
          <div className="mx-4 my-2 rounded-lg bg-red-50 px-4 py-3 text-sm text-red-700 border border-red-200">
            ⚠️ {error}
          </div>
        )}

        <div ref={bottomRef} />
      </div>

      {/* Invoerveld */}
      <div className="border-t border-gray-200 p-3">
        <div className="flex gap-2 items-end">
          <textarea
            ref={inputRef}
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Typ uw vraag hier… (Enter om te versturen)"
            rows={1}
            disabled={isLoading}
            className={cn(
              'flex-1 resize-none rounded-xl border border-gray-300 bg-gray-50 px-4 py-2.5 text-sm',
              'placeholder:text-gray-400 focus:outline-none focus:ring-2 focus:ring-brand-600',
              'disabled:cursor-not-allowed disabled:opacity-50',
              'min-h-[42px] max-h-[120px]'
            )}
            style={{ height: 'auto' }}
            onInput={e => {
              const t = e.target as HTMLTextAreaElement;
              t.style.height = 'auto';
              t.style.height = Math.min(t.scrollHeight, 120) + 'px';
            }}
          />
          <Button
            onClick={sendMessage}
            disabled={!input.trim() || isLoading}
            size="icon"
            className="h-[42px] w-[42px] shrink-0"
          >
            {isLoading
              ? <Loader2 size={16} className="animate-spin" />
              : <Send size={16} />
            }
          </Button>
        </div>
        <p className="mt-1.5 text-center text-xs text-gray-400">
          Shift+Enter voor nieuwe regel
        </p>
      </div>
    </div>
  );
}

