/**
 * app/api/chat/route.ts
 * Kern-chatendpoint met Server-Sent Events streaming.
 *
 * Stroom per aanroep:
 *  1. Rate-limit check op IP
 *  2. Input-validatie & sanitering
 *  3. DB: live voertuigdata ophalen → dynamische system-prompt bouwen
 *  4. DB: berichtgeschiedenis laden (context)
 *  5. LM Studio aanroepen met stream: true
 *  6. Tokens token-voor-token naar client streamen via SSE
 *  7. DB: volledig bot-antwoord opslaan
 */

import { NextRequest } from 'next/server';
import { buildSystemPrompt }            from '@/lib/llm';
import {
  saveMessage,
  getConversationMessages,
  createConversation,
}                                        from '@/lib/db';
import { checkRateLimit }               from '@/lib/rateLimit';
import { getUser }                      from '@/lib/auth';

// Voorkom Next.js static caching op dit streaming endpoint
export const dynamic = 'force-dynamic';

/** POST /api/chat */
export async function POST(request: NextRequest) {
  // ─── Rate limiting ───────────────────────────────────────────
  const ip = (
    request.headers.get('x-forwarded-for')?.split(',')[0] ??
    request.headers.get('x-real-ip') ??
    '127.0.0.1'
  ).trim();

  const rl = checkRateLimit(ip, 30, 60_000);
  if (!rl.allowed) {
    return sseError('Te veel verzoeken. Probeer het over een minuut opnieuw.', 429, {
      'X-RateLimit-Remaining': '0',
      'X-RateLimit-Reset':     rl.resetAt.toString(),
    });
  }

  // ─── Input verwerking ────────────────────────────────────────
  let body: { message?: unknown; conversationId?: unknown };
  try {
    body = await request.json();
  } catch {
    return sseError('Ongeldig JSON-verzoek.', 400);
  }

  const rawMsg = body.message;
  if (!rawMsg || typeof rawMsg !== 'string') {
    return sseError('Bericht is verplicht.', 400);
  }

  // Saniteer: max 2000 tekens, geen HTML-tags
  const userMessage = rawMsg.trim().slice(0, 2000).replace(/[<>]/g, '');
  if (!userMessage) return sseError('Leeg bericht.', 400);

  // ─── Gebruiker & conversatie ─────────────────────────────────
  const authUser = await getUser().catch(() => null);
  const userId   = authUser?.userId ?? `guest_${ip.replace(/\./g, '_')}`;

  let conversationId =
    typeof body.conversationId === 'string' && body.conversationId.trim()
      ? body.conversationId.trim()
      : null;

  if (!conversationId) {
    conversationId = await createConversation(userId);
  }

  // Sla gebruikersbericht op
  await saveMessage({ conversationId, role: 'user', content: userMessage }).catch(
    err => console.error('[Chat] Opslaan gebruikersbericht mislukt:', err)
  );

  // ─── Context opbouwen ────────────────────────────────────────
  const [systemPrompt, history] = await Promise.all([
    buildSystemPrompt(conversationId),
    getConversationMessages(conversationId).catch(() => []),
  ]);

  // Neem laatste 10 berichten mee als context (exclusief het zojuist opgeslagen bericht)
  const contextMessages = history
    .filter(m => m.role !== 'system')
    .slice(-10)
    .map(m => ({ role: m.role as 'user' | 'assistant', content: m.content }));

  const messages = [
    { role: 'system'    as const, content: systemPrompt },
    ...contextMessages,
    { role: 'user'      as const, content: userMessage  },
  ];

  console.log(
    `[Chat] ConvID=${conversationId} | User=${userId} | Msg="${userMessage.slice(0, 60)}"`
  );

  // ─── SSE streaming ───────────────────────────────────────────
  const llmUrl   = process.env.LLM_URL   ?? 'http://localhost:1234/v1/chat/completions';
  const llmModel = process.env.LLM_MODEL ?? 'local-model';
  const timeout  = Number(process.env.LLM_TIMEOUT ?? 30_000);
  const encoder  = new TextEncoder();

  const stream = new ReadableStream({
    async start(controller) {
      const emit = (data: unknown) =>
        controller.enqueue(encoder.encode(`data: ${JSON.stringify(data)}\n\n`));

      // Stuur conversationId meteen naar de client
      emit({ conversationId });

      let fullResponse = '';

      try {
        const llmRes = await fetch(llmUrl, {
          method:  'POST',
          headers: { 'Content-Type': 'application/json' },
          body:    JSON.stringify({
            model:       llmModel,
            messages,
            stream:      true,
            temperature: 0.7,
            max_tokens:  1024,
          }),
          signal: AbortSignal.timeout(timeout),
        });

        if (!llmRes.ok) {
          throw new Error(`LLM HTTP ${llmRes.status}: ${llmRes.statusText}`);
        }

        const reader  = llmRes.body?.getReader();
        if (!reader) throw new Error('Geen response body ontvangen van LLM');

        const decoder = new TextDecoder();

        outer: while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          for (const line of decoder.decode(value, { stream: true }).split('\n')) {
            if (!line.startsWith('data: ')) continue;
            const raw = line.slice(6).trim();

            if (raw === '[DONE]') {
              // Bot-antwoord opslaan in DB
              if (fullResponse) {
                await saveMessage({
                  conversationId: conversationId!,
                  role:           'assistant',
                  content:        fullResponse,
                  llmModelUsed:   llmModel,
                }).catch(err => console.error('[Chat] Opslaan bot-antwoord mislukt:', err));
              }
              controller.enqueue(encoder.encode('data: [DONE]\n\n'));
              controller.close();
              break outer;
            }

            try {
              const token: string =
                JSON.parse(raw)?.choices?.[0]?.delta?.content ?? '';
              if (token) {
                fullResponse += token;
                emit({ token });
              }
            } catch { /* ongeldige JSON-chunk → overslaan */ }
          }
        }

        // Fallback: stream eindigde zonder [DONE]
        if (fullResponse && !controller.desiredSize) return;
        if (fullResponse) {
          await saveMessage({
            conversationId: conversationId!,
            role:           'assistant',
            content:        fullResponse,
            llmModelUsed:   llmModel,
          }).catch(console.error);
          controller.enqueue(encoder.encode('data: [DONE]\n\n'));
          controller.close();
        }
      } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        console.error('[Chat] LLM fout:', msg);
        emit({ error: `Verbindingsfout met AI: ${msg}` });
        controller.close();
      }
    },
  });

  return new Response(stream, {
    headers: {
      'Content-Type':        'text/event-stream',
      'Cache-Control':       'no-cache, no-transform',
      'Connection':          'keep-alive',
      'X-Accel-Buffering':   'no',
      'X-RateLimit-Remaining': rl.remaining.toString(),
    },
  });
}

// ── Hulpfunctie: geef SSE-fout terug ──────────────────────────
function sseError(
  message: string,
  status  = 500,
  extraHeaders: Record<string, string> = {}
): Response {
  return new Response(
    `data: ${JSON.stringify({ error: message })}\n\n`,
    {
      status,
      headers: {
        'Content-Type': 'text/event-stream',
        ...extraHeaders,
      },
    }
  );
}
